   151→// removeDeletedKinds inspects the storage map and modifies it in place by removing storage for kinds that have been deleted.
   152→// versionedResourcesStorageMap mirrors the field on APIGroupInfo, it's a map from version to resource to the storage.
   153→func (e *resourceExpirationEvaluator) RemoveDeletedKinds(groupName string, versioner runtime.ObjectVersioner, versionedResourcesStorageMap map[string]map[string]rest.Storage) {
   154→	versionsToRemove := sets.NewString()
   155→	for apiVersion := range sets.StringKeySet(versionedResourcesStorageMap) {
   156→		versionToResource := versionedResourcesStorageMap[apiVersion]
   157→		resourcesToRemove := sets.NewString()
   158→		for resourceName, resourceServingInfo := range versionToResource {
   159→			if !e.shouldServe(schema.GroupVersion{Group: groupName, Version: apiVersion}, versioner, resourceServingInfo) {
   160→				resourcesToRemove.Insert(resourceName)
   161→			}
   162→		}
   163→
   164→		for resourceName := range versionedResourcesStorageMap[apiVersion] {
   165→			if !shouldRemoveResourceAndSubresources(resourcesToRemove, resourceName) {
   166→				continue
   167→			}
   168→
   169→			klog.V(1).Infof("Removing resource %v.%v.%v because it is time to stop serving it per APILifecycle.", resourceName, apiVersion, groupName)
   170→			storage := versionToResource[resourceName]
   171→			storage.Destroy()
   172→			delete(versionToResource, resourceName)
   173→		}
   174→		versionedResourcesStorageMap[apiVersion] = versionToResource
   175→
   176→		if len(versionedResourcesStorageMap[apiVersion]) == 0 {
   177→			versionsToRemove.Insert(apiVersion)
   178→		}
   179→	}
   180→
   181→	for _, apiVersion := range versionsToRemove.List() {
   182→		klog.V(1).Infof("Removing version %v.%v because it is time to stop serving it because it has no resources per APILifecycle.", apiVersion, groupName)
   183→		delete(versionedResourcesStorageMap, apiVersion)
   184→	}
   185→}
   186→
   187→func shouldRemoveResourceAndSubresources(resourcesToRemove sets.String, resourceName string) bool {
   188→	for _, resourceToRemove := range resourcesToRemove.List() {
   189→		if resourceName == resourceToRemove {
   190→			return true
   191→		}
   192→		// our API works on nesting, so you can have deployments, deployments/status, and deployments/scale.  Not all subresources
   193→		// serve the parent type, but if the parent type (deployments in this case), has been removed, it's subresources should be removed too.
   194→		if strings.HasPrefix(resourceName, resourceToRemove+"/") {
   195→			return true
   196→		}
   197→	}
   198→	return false
   199→}
