   613→// InstrumentRouteFunc works like Prometheus' InstrumentHandlerFunc but wraps
   614→// the go-restful RouteFunction instead of a HandlerFunc plus some Kubernetes endpoint specific information.
   615→func InstrumentRouteFunc(verb, group, version, resource, subresource, scope, component string, deprecated bool, removedRelease string, routeFunc restful.RouteFunction) restful.RouteFunction {
   616→	return restful.RouteFunction(func(req *restful.Request, response *restful.Response) {
   617→		requestReceivedTimestamp, ok := request.ReceivedTimestampFrom(req.Request.Context())
   618→		if !ok {
   619→			requestReceivedTimestamp = time.Now()
   620→		}
   621→
   622→		delegate := &ResponseWriterDelegator{ResponseWriter: response.ResponseWriter}
   623→
   624→		rw := responsewriter.WrapForHTTP1Or2(delegate)
   625→		response.ResponseWriter = rw
   626→
   627→		routeFunc(req, response)
   628→
   629→		MonitorRequest(req.Request, verb, group, version, resource, subresource, scope, component, deprecated, removedRelease, delegate.Status(), delegate.ContentLength(), time.Since(requestReceivedTimestamp))
   630→	})
   631→}
