   633→// InstrumentHandlerFunc works like Prometheus' InstrumentHandlerFunc but adds some Kubernetes endpoint specific information.
   634→func InstrumentHandlerFunc(verb, group, version, resource, subresource, scope, component string, deprecated bool, removedRelease string, handler http.HandlerFunc) http.HandlerFunc {
   635→	return func(w http.ResponseWriter, req *http.Request) {
   636→		requestReceivedTimestamp, ok := request.ReceivedTimestampFrom(req.Context())
   637→		if !ok {
   638→			requestReceivedTimestamp = time.Now()
   639→		}
   640→
   641→		delegate := &ResponseWriterDelegator{ResponseWriter: w}
   642→		w = responsewriter.WrapForHTTP1Or2(delegate)
   643→
   644→		handler(w, req)
   645→
   646→		MonitorRequest(req, verb, group, version, resource, subresource, scope, component, deprecated, removedRelease, delegate.Status(), delegate.ContentLength(), time.Since(requestReceivedTimestamp))
   647→	}
   648→}
