   650→// NormalizedVerb returns normalized verb
   651→func NormalizedVerb(req *http.Request) string {
   652→	verb := req.Method
   653→	requestInfo, ok := request.RequestInfoFrom(req.Context())
   654→	if ok {
   655→		// If we can find a requestInfo, we can get a scope, and then
   656→		// we can convert GETs to LISTs when needed.
   657→		scope := CleanScope(requestInfo)
   658→		verb = CanonicalVerb(strings.ToUpper(verb), scope)
   659→	}
   660→
   661→	// mark APPLY requests, WATCH requests and CONNECT requests correctly.
   662→	return CleanVerb(verb, req, requestInfo)
   663→}
   664→
   665→// CleanScope returns the scope of the request.
   666→func CleanScope(requestInfo *request.RequestInfo) string {
   667→	if requestInfo.Name != "" || requestInfo.Verb == "create" {
   668→		return "resource"
   669→	}
   670→	if requestInfo.Namespace != "" {
   671→		return "namespace"
   672→	}
   673→	if requestInfo.IsResourceRequest {
   674→		return "cluster"
   675→	}
   676→	// this is the empty scope
   677→	return ""
   678→}
   679→
   680→// CleanListScope computes the request scope for metrics.
