   682→// Note that normally we would use CleanScope for computation.
   683→// But due to the same reasons mentioned in determineRequestNamespaceAndName we cannot.
   684→func CleanListScope(ctx context.Context, opts *metainternalversion.ListOptions) string {
   685→	namespace, name := determineRequestNamespaceAndName(ctx, opts)
   686→	if len(name) > 0 {
